// ===== JWT 登录处理 =====
var crypto = global.get('crypto');

// JWT 密钥与令牌有效期配置 (生产环境通过环境变量覆盖)
var JWT_SECRET = process.env.JWT_SECRET || 'focus-fitness-os-jwt-secret-2024';
var ACCESS_TOKEN_TTL = 3600;              // Access Token 有效期: 1小时
var REFRESH_TOKEN_TTL = 7 * 24 * 3600;    // Refresh Token 有效期: 7天

// base64url 编码工具函数
function base64url(str) {
    return Buffer.from(str).toString('base64')
        .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}
function base64urlBuf(buf) {
    return buf.toString('base64')
        .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

// 签发 Access Token (HMAC-SHA256)
function signAccessToken(user_id, username) {
    var header = { alg: 'HS256', typ: 'JWT' };
    var now = Math.floor(Date.now() / 1000);
    var payload = {
        user_id: user_id,
        username: username,
        iat: now,
        exp: now + ACCESS_TOKEN_TTL
    };
    var headerB64 = base64url(JSON.stringify(header));
    var payloadB64 = base64url(JSON.stringify(payload));
    var data = headerB64 + '.' + payloadB64;
    var sig = crypto.createHmac('sha256', JWT_SECRET).update(data).digest();
    return data + '.' + base64urlBuf(sig);
}

// 生成 Refresh Token (64字节随机 hex)
function generateRefreshToken() {
    return crypto.randomBytes(64).toString('hex');
}

// ===== 用户验证 =====
// 用户库 (生产环境应替换为数据库 + bcrypt, 此处为演示用)
// TODO: 生产环境集成 bcrypt 与持久化用户存储
var users = global.get('auth_users');
if (!users) {
    users = [
        { user_id: 1, username: 'admin', password: 'admin123' }
    ];
    global.set('auth_users', users);
}

var body = msg.payload || {};
var username = body.username;
var password = body.password;

// 参数校验
if (!username || !password) {
    msg.payload = JSON.stringify({ code: 1, error: '用户名和密码不能为空' });
    msg.statusCode = 400;
    return msg;
}

// 查找用户
var user = null;
for (var i = 0; i < users.length; i++) {
    if (users[i].username === username && users[i].password === password) {
        user = users[i];
        break;
    }
}

if (!user) {
    msg.payload = JSON.stringify({ code: 1, error: '用户名或密码错误' });
    msg.statusCode = 401;
    return msg;
}

// 签发令牌
var accessToken = signAccessToken(user.user_id, user.username);
var refreshToken = generateRefreshToken();

// 存储 Refresh Token 到 global context
var refreshStore = global.get('refresh_tokens') || {};
var now = Math.floor(Date.now() / 1000);
refreshStore[refreshToken] = {
    user_id: user.user_id,
    username: user.username,
    created_at: now,
    expires_at: now + REFRESH_TOKEN_TTL
};
global.set('refresh_tokens', refreshStore);

// 返回令牌 (OAuth2 标准扁平结构, 与 Flutter AuthService.AuthTokens.fromJson 契约一致)
msg.payload = JSON.stringify({
    access_token: accessToken,
    refresh_token: refreshToken,
    token_type: 'Bearer',
    expires_in: ACCESS_TOKEN_TTL
});
msg.statusCode = 200;
return msg;

// ===== JWT 刷新处理 =====
var crypto = global.get('crypto');

var JWT_SECRET = process.env.JWT_SECRET || 'focus-fitness-os-jwt-secret-2024';
var ACCESS_TOKEN_TTL = 3600;

// base64url 编码工具函数
function base64url(str) {
    return Buffer.from(str).toString('base64')
        .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}
function base64urlBuf(buf) {
    return buf.toString('base64')
        .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

// 签发 Access Token (HMAC-SHA256)
function signAccessToken(user_id, username) {
    var header = { alg: 'HS256', typ: 'JWT' };
    var now = Math.floor(Date.now() / 1000);
    var payload = {
        user_id: user_id,
        username: username,
        iat: now,
        exp: now + ACCESS_TOKEN_TTL
    };
    var headerB64 = base64url(JSON.stringify(header));
    var payloadB64 = base64url(JSON.stringify(payload));
    var data = headerB64 + '.' + payloadB64;
    var sig = crypto.createHmac('sha256', JWT_SECRET).update(data).digest();
    return data + '.' + base64urlBuf(sig);
}

// 从 Authorization 头提取 Bearer 令牌
var authHeader = msg.req.headers['authorization'] || '';
var token = '';
if (authHeader.indexOf('Bearer ') === 0) {
    token = authHeader.substring(7);
}

if (!token) {
    msg.payload = JSON.stringify({ code: 1, error: '缺少 Refresh Token' });
    msg.statusCode = 401;
    return msg;
}

// 验证 Refresh Token 是否存在于 global context
var refreshStore = global.get('refresh_tokens') || {};
var tokenData = refreshStore[token];

if (!tokenData) {
    msg.payload = JSON.stringify({ code: 1, error: '无效的 Refresh Token' });
    msg.statusCode = 401;
    return msg;
}

// 检查 Refresh Token 是否过期
var now = Math.floor(Date.now() / 1000);
if (now > tokenData.expires_at) {
    // 过期则删除并要求重新登录
    delete refreshStore[token];
    global.set('refresh_tokens', refreshStore);
    msg.payload = JSON.stringify({ code: 1, error: 'Refresh Token 已过期, 请重新登录' });
    msg.statusCode = 401;
    return msg;
}

// 签发新的 Access Token (保留原 Refresh Token)
var accessToken = signAccessToken(tokenData.user_id, tokenData.username);

// 返回令牌 (OAuth2 标准扁平结构, 与 Flutter AuthService.AuthTokens.fromJson 契约一致)
msg.payload = JSON.stringify({
    access_token: accessToken,
    refresh_token: token,
    token_type: 'Bearer',
    expires_in: ACCESS_TOKEN_TTL
});
msg.statusCode = 200;
return msg;

// ===== JWT 验证处理 =====
var crypto = global.get('crypto');

var JWT_SECRET = process.env.JWT_SECRET || 'focus-fitness-os-jwt-secret-2024';

// base64url 解码辅助 (还原为标准 base64)
function base64urlDecode(str) {
    str = str.replace(/-/g, '+').replace(/_/g, '/');
    while (str.length % 4) { str += '='; }
    return str;
}

// 从 Authorization 头提取 Bearer 令牌
var authHeader = msg.req.headers['authorization'] || '';
var token = '';
if (authHeader.indexOf('Bearer ') === 0) {
    token = authHeader.substring(7);
}

if (!token) {
    msg.payload = JSON.stringify({ code: 1, error: '缺少 Access Token' });
    msg.statusCode = 401;
    return msg;
}

// 解析 JWT (header.payload.signature)
var parts = token.split('.');
if (parts.length !== 3) {
    msg.payload = JSON.stringify({ code: 1, error: '令牌格式无效' });
    msg.statusCode = 401;
    return msg;
}

var headerB64 = parts[0];
var payloadB64 = parts[1];
var signatureB64 = parts[2];
var data = headerB64 + '.' + payloadB64;

// 验证签名 (HMAC-SHA256)
var expectedSig = crypto.createHmac('sha256', JWT_SECRET).update(data).digest();
var expectedSigB64 = expectedSig.toString('base64')
    .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');

// 签名比对 (长度一致后再逐字符比较, 降低时序攻击风险)
if (expectedSigB64.length !== signatureB64.length) {
    msg.payload = JSON.stringify({ code: 1, error: '令牌签名无效' });
    msg.statusCode = 401;
    return msg;
}
var diff = 0;
for (var i = 0; i < expectedSigB64.length; i++) {
    diff |= expectedSigB64.charCodeAt(i) ^ signatureB64.charCodeAt(i);
}
if (diff !== 0) {
    msg.payload = JSON.stringify({ code: 1, error: '令牌签名无效' });
    msg.statusCode = 401;
    return msg;
}

// 解析 payload
var payloadStr = Buffer.from(base64urlDecode(payloadB64), 'base64').toString();
var payload;
try {
    payload = JSON.parse(payloadStr);
} catch (e) {
    msg.payload = JSON.stringify({ code: 1, error: '令牌负载解析失败' });
    msg.statusCode = 401;
    return msg;
}

// 检查过期时间
var now = Math.floor(Date.now() / 1000);
if (payload.exp && now > payload.exp) {
    msg.payload = JSON.stringify({ code: 1, error: '令牌已过期' });
    msg.statusCode = 401;
    return msg;
}

// 验证通过 (verify 端点保留 {code, data, message} 业务响应格式)
msg.payload = JSON.stringify({
    code: 0,
    data: {
        valid: true,
        user_id: payload.user_id,
        username: payload.username,
        exp: payload.exp,
        iat: payload.iat
    },
    message: '令牌有效'
});
msg.statusCode = 200;
return msg;

// 错误格式化: 捕获 Flow 执行异常, 返回统一错误响应
var errMsg = msg.error ? msg.error.message : '认证服务内部错误';
msg.payload = JSON.stringify({ code: 1, error: errMsg });
msg.statusCode = 500;
return msg;
